/* adm-master-centerBatch-sql-oracle.xml  insertIntfTableCenterList */
INSERT INTO TADMIN_INTF_CT(
	  CTKEY
	, CTTYPE
	, CTNAME
	, ZIPCODE
	, ADDRESS1
	, ADDRESS2
	, CLOSDATE
	, REQUESTDT
	, INTERFACE_ID
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES (
	  #{ctkey}
	, #{cttype}
	, #{ctname}
	, #{zipcode}
	, #{addr1}
	, #{addr2}
	, #{acKey}
	, #{requestDt}
	, #{interfaceId}
	, TO_CHAR(CURRENT_TIMESTAMP ,'YYYYMMDDHH24MISS')
	, #{interfaceUrkey}
	, TO_CHAR(CURRENT_TIMESTAMP ,'YYYYMMDDHH24MISS')
	, #{interfaceUrkey}
)
